def get_head_candidate(terms):
    words = terms.split()
    if words[-1].isalpha():  # Last word is likely to be the head
        return words[-1]
    elif words[-2].endswith('.'):  # Consider previous word if last contains a period (suggesting this is an adjective phrase)
        return words[words.index(words[-2].split('.')[0]) - 1]
    else:  # Default case, take the first verb-like word as head
        for i in range(len(words) - 1, -1, -1):
            if words[i].lower() in {"shows", "exhibits", "prescribes", "has", "feels"}:
                return words[i]
    return None

def parse_dependencies(text):
    terms = " ".join(text.split())  # Remove extra spaces
    head = get_head_candidate(terms)
    head_pos = terms.find(head)

    result = {}
    for position, term in enumerate(text.split()):
        if term == "acute":
            result[head_pos] = "distress"
        elif term == "mild":
            result[head_pos] = "fever"
